291→const MissionOrders: React.FC<MissionOrdersProps> = ({ onBack, user, onNavigate }) => {
292→  const [missions, setMissions] = useState<MissionOrder[]>(DEMO_MISSIONS);
293→  const [searchQuery, setSearchQuery] = useState('');
294→  const [statusFilter, setStatusFilter] = useState<MissionStatus | 'all'>('all');
295→  const [expandedMission, setExpandedMission] = useState<string | null>(null);
296→  const [sortBy, setSortBy] = useState<'date' | 'budget' | 'score'>('date');
297→  const [proofModal, setProofModal] = useState<{ missionId: string; recId: string } | null>(null);
298→  const [proofForm, setProofForm] = useState({ type: 'lien' as ProofType, description: '', url: '' });
299→
300→  const kpis = useMemo(() => ({
301→    total: missions.length,
302→    nouveau: missions.filter(m => m.status === 'nouveau').length,
303→    en_cours: missions.filter(m => ['accepte', 'en_cours', 'livraison'].includes(m.status)).length,
304→    termine: missions.filter(m => m.status === 'termine').length,
305→    refuse: missions.filter(m => m.status === 'refuse').length,
306→    totalBudget: missions.filter(m => m.status !== 'refuse').reduce((sum, m) => sum + m.budget, 0),
307→    avgScore: Math.round(missions.reduce((sum, m) => sum + m.aeoScore, 0) / missions.length),
308→    escrowBloque: missions.filter(m => m.escrowStatus === 'bloque' || m.escrowStatus === 'en_validation').reduce((s, m) => s + m.budget, 0),
309→  }), [missions]);
310→
311→  const filteredMissions = useMemo(() => {
312→    let filtered = missions;
313→    if (statusFilter !== 'all') filtered = filtered.filter(m => m.status === statusFilter);
314→    if (searchQuery.trim()) {
315→      const q = searchQuery.toLowerCase();
316→      filtered = filtered.filter(m =>
317→        m.clientName.toLowerCase().includes(q) || m.clientCompany.toLowerCase().includes(q) ||
318→        m.analyzedUrl.toLowerCase().includes(q) || m.id.toLowerCase().includes(q)
319→      );
320→    }
321→    return [...filtered].sort((a, b) => {
322→      if (sortBy === 'budget') return b.budget - a.budget;
323→      if (sortBy === 'score') return a.aeoScore - b.aeoScore;
324→      return new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime();
325→    });
326→  }, [missions, statusFilter, searchQuery, sortBy]);
327→
328→  const handleStatusChange = (missionId: string, newStatus: MissionStatus) => {
329→    setMissions(prev => prev.map(m => {
330→      if (m.id !== missionId) return m;
331→      const updates: Partial<MissionOrder> = { status: newStatus, updatedAt: new Date().toISOString() };
332→      if (newStatus === 'accepte') updates.escrowStatus = 'bloque';
333→      if (newStatus === 'livraison') updates.escrowStatus = 'en_validation';
334→      if (newStatus === 'termine') updates.escrowStatus = 'libere';
335→      return { ...m, ...updates };
336→    }));
337→  };
338→
339→  const handleToggleRecommendation = (missionId: string, recId: string) => {
340→    setMissions(prev => prev.map(m => {
341→      if (m.id !== missionId) return m;
342→      const completed = m.completedRecommendations || [];
343→      const isCompleted = completed.includes(recId);
344→      return {
345→        ...m,
346→        completedRecommendations: isCompleted ? completed.filter(id => id !== recId) : [...completed, recId],
347→        updatedAt: new Date().toISOString(),
348→      };
349→    }));
350→  };
351→
352→  const handleSubmitProof = () => {
353→    if (!proofModal || !proofForm.description.trim()) return;
354→    setMissions(prev => prev.map(m => {
355→      if (m.id !== proofModal.missionId) return m;
356→      return {
357→        ...m,
358→        recommendations: m.recommendations.map(r => {
359→          if (r.id !== proofModal.recId) return r;
360→          return {
361→            ...r,
362→            proof: {
363→              type: proofForm.type,
364→              label: proofForm.type === 'lien' ? 'Lien livrable' : proofForm.type === 'code' ? 'Code livré' : proofForm.type === 'capture' ? 'Capture d\'écran' : 'Rapport d\'audit',
365→              url: proofForm.url,
366→              description: proofForm.description,
367→              submittedAt: new Date().toISOString(),
368→            },
369→            platformValidation: 'en_attente' as PlatformValidation,
370→          };
371→        }),
372→        updatedAt: new Date().toISOString(),
373→      };
374→    }));
375→    setProofModal(null);
376→    setProofForm({ type: 'lien', description: '', url: '' });
377→  };
378→
379→  const handleReaudit = (missionId: string) => {
380→    setMissions(prev => prev.map(m => m.id === missionId ? { ...m, isReauditing: true } : m));
381→    // Simulated re-audit with random improvement
382→    setTimeout(() => {
383→      setMissions(prev => prev.map(m => {
384→        if (m.id !== missionId) return m;
385→        const improvement = Math.floor(Math.random() * 30) + 15;
386→        const newScore = Math.min(100, m.aeoScore + improvement);
